// ═══════════════════════════════════════════════════════
// CLASSIFICAR LEADS — Primeiro contato + Follow-up
// ═══════════════════════════════════════════════════════
// ▶ Persona configurável (altere aqui):
const NOME_CONSULTOR = 'Maya';

const now = new Date();
const items = $input.all();
const result = [];

for (const item of items) {
  const d = item.json;
  const status = (d['ENVIOU MSG'] || '').toString().trim().toUpperCase();
  const optout = (d['OPT_OUT'] || '').toString().trim().toUpperCase();

  if (optout === 'SIM') continue;
  if (status === 'PROCESSANDO' || status === 'ERRO') continue;

  if (!status || status === 'PENDENTE') {
    result.push({ json: { ...d, tipo_disparo: 'primeiro_contato', NOME_CONSULTOR } });
  } else if (status === 'FEITO') {
    const dataEnvio = (d['DATA DO ENVIO'] || '').toString().trim();
    if (!dataEnvio) continue;
    const parts = dataEnvio.split(' ')[0].split('/');
    if (parts.length < 3) continue;
    const sendDate = new Date(parseInt(parts[2]), parseInt(parts[1]) - 1, parseInt(parts[0]));
    const daysSince = Math.floor((now - sendDate) / 86400000);
    const followups = parseInt(d.FOLLOWUP_COUNT || '0') || 0;

    if (followups === 0 && daysSince >= 3) {
      result.push({ json: { ...d, tipo_disparo: 'followup_1', NOME_CONSULTOR } });
    } else if (followups === 1 && daysSince >= 7) {
      result.push({ json: { ...d, tipo_disparo: 'followup_2', NOME_CONSULTOR } });
    }
  }
}

return result;

// ═══════════════════════════════════════════════════════
// HIGIENIZAR DADOS — Telefone, Nome, Empresa
// Com fallback de nome para EMPRESA
// ═══════════════════════════════════════════════════════
const skip = /^(ass|cont|contab|contábil|emp|serv|ltda|eireli|me|ss|dpto|dep)/i;

return $input.all().map(item => {
  const d = item.json;

  // --- Telefone ---
  let phone = (d.WHATSAPP || '').toString().replace(/\D/g, '');
  if (phone.length === 11 || phone.length === 10) phone = '55' + phone;
  if (phone.startsWith('5555')) phone = phone.slice(2);
  const telefone_valido = phone.length >= 12 && phone.length <= 13 && phone.startsWith('55');

  // --- Nome (extrair primeiro nome de pessoa) ---
  let nomeRaw = (d.NOME || '').toString().trim();
  nomeRaw = nomeRaw.replace(/^[+\-\d\s*×÷=.]+/, '').trim();
  nomeRaw = nomeRaw.replace(/\s*[+×÷=]+\s*.*/g, '').trim();
  nomeRaw = nomeRaw.replace(/\(.*?\)/g, '').trim();
  let primeiro_nome = nomeRaw.split(/[\s,;\/]+/)[0] || '';
  if (/^\d+$/.test(primeiro_nome) || primeiro_nome.length < 3) primeiro_nome = '';
  if (skip.test(primeiro_nome)) primeiro_nome = '';
  if (primeiro_nome && primeiro_nome === primeiro_nome.toUpperCase()) {
    primeiro_nome = primeiro_nome.charAt(0).toUpperCase() + primeiro_nome.slice(1).toLowerCase();
  }

  // --- Empresa ---
  let empresa = (d.EMPRESA || '').toString().trim();
  if (empresa.length < 3) empresa = '';

  // --- Fallback: tentar nome de pessoa na EMPRESA ---
  if (!primeiro_nome && empresa) {
    const palavras = empresa.split(/\s+/);
    if (palavras.length <= 3) {
      const candidato = palavras[0];
      if (candidato.length >= 3 && !/^\d+$/.test(candidato) && !skip.test(candidato)) {
        primeiro_nome = candidato;
        if (primeiro_nome === primeiro_nome.toUpperCase()) {
          primeiro_nome = primeiro_nome.charAt(0).toUpperCase() + primeiro_nome.slice(1).toLowerCase();
        }
      }
    }
  }

  // --- Nome para saudação (fallback empresa) ---
  let nome_saudacao = primeiro_nome;
  if (!nome_saudacao && empresa) {
    nome_saudacao = 'pessoal da ' + empresa;
  }

  let produto = (d['PRODUTO DE INTERESSE'] || '').toString().trim();

  return { json: { ...d, telefone_limpo: phone, telefone_valido, nome_limpo: primeiro_nome, nome_saudacao, empresa_limpa: empresa, produto_limpo: produto } };
}).filter(item => item.json.telefone_valido);

// ═══════════════════════════════════════════════════════
// WARMUP PROGRESSIVO — Volume dinâmico por semana
// ═══════════════════════════════════════════════════════
// ▶ Ajuste a data na primeira ativação:
const DATA_INICIO_WARMUP = '2026-04-10';
const EXECUCOES_POR_DIA = 4; // Deve bater com o cron (9h,11h,14h,16h)

const inicio = new Date(DATA_INICIO_WARMUP);
const agora = new Date();
const dias = Math.max(0, Math.floor((agora - inicio) / 86400000));

let maxPorDia;
if (dias < 7)       maxPorDia = 20;   // Sem 1
else if (dias < 14) maxPorDia = 50;   // Sem 2
else if (dias < 21) maxPorDia = 100;  // Sem 3
else if (dias < 28) maxPorDia = 200;  // Sem 4
else                maxPorDia = 300;  // Sem 5+

const maxPorExec = Math.ceil(maxPorDia / EXECUCOES_POR_DIA);

// Priorizar primeiro contato (70%) sobre follow-up (30%)
const items = $input.all();
const primeiro = items.filter(i => i.json.tipo_disparo === 'primeiro_contato');
const followup = items.filter(i => i.json.tipo_disparo !== 'primeiro_contato');

const maxP = Math.ceil(maxPorExec * 0.7);
const maxF = Math.floor(maxPorExec * 0.3);

const selecionados = [
  ...primeiro.slice(0, maxP),
  ...followup.slice(0, maxF)
];

return selecionados.slice(0, maxPorExec);

// ═══════════════════════════════════════════════════════
// PREPARAR DISPARO — 1º Contato + Follow-up
// Usa CONTEXTO / TOM / OBJETIVO da planilha
// ═══════════════════════════════════════════════════════
const item = $input.first().json;
const nome = item.nome_saudacao || '';
const empresa = item.empresa_limpa || '';
const produto = (item.produto_limpo || '').toLowerCase();
const consultor = item.NOME_CONSULTOR || 'Maya';
const tipo = item.tipo_disparo || 'primeiro_contato';
const contexto = (item.CONTEXTO || '').toString().trim();
const tom = (item.TOM || '').toString().trim().toLowerCase();
const objetivo = (item.OBJETIVO_DISPARO || '').toString().trim().toLowerCase();

// --- Variante (randomização real) ---
const variants = ['A', 'B', 'C'];
const variante = variants[Math.floor(Math.random() * 3)];

// --- Saudação ---
const saudacao = nome ? 'Oi, ' + nome + ', tudo bem?' : 'Oi, tudo bem?';

// --- Gancho por produto ---
let gancho = 'malotes e materiais personalizados';
let detalhe = 'transporte de documentos, separação por cliente, esse tipo de coisa';
if (produto.includes('quadro')) {
  gancho = 'quadros fiscais e materiais de conformidade';
  detalhe = 'conformidade legal, organização visual do estabelecimento';
} else if (produto.includes('pasta l')) {
  gancho = 'pastas L e materiais de organização';
  detalhe = 'organização de documentos, atendimento a clientes';
} else if (produto.includes('pasta') || produto.includes('ctps') || produto.includes('capa')) {
  gancho = 'pastas e capas pra organização documental';
  detalhe = 'organização de documentos, rotina de RH e atendimento';
} else if (produto.includes('alvará') || produto.includes('porta alvar')) {
  gancho = 'porta alvarás e materiais de conformidade';
  detalhe = 'conformidade legal, apresentação profissional do escritório';
} else if (produto.includes('brinde')) {
  gancho = 'materiais personalizados com a marca da empresa';
  detalhe = 'fortalecimento da marca, relacionamento com clientes';
}

// --- Modificador CONTEXTO (personalização com logo) ---
let refExtra = '';
if (contexto && (contexto.includes('logo') || contexto.includes('personalização')) && !gancho.includes('personaliz')) {
  refExtra = ', inclusive com personalização da marca';
}

let msg = '';
const maxChars = tipo === 'primeiro_contato' ? 500 : 350;
const temEmpresaNoNome = nome.startsWith('pessoal');

if (tipo === 'primeiro_contato') {
  // ═══ PRIMEIRO CONTATO ═══
  if (variante === 'A') {
    if (empresa && !temEmpresaNoNome) {
      msg = saudacao + '\n\nAqui é a ' + consultor + ', assistente da Federal Malotes.\n\nVi que a ' + empresa + ' é do ramo contábil. A gente fornece ' + gancho + refExtra + ' que ajudam bastante na organização do dia a dia do escritório.\n\nPosso te mostrar alguns modelos que costumam fazer sentido pra vocês?';
    } else {
      msg = saudacao + '\n\nAqui é a ' + consultor + ', assistente da Federal Malotes.\n\nA gente trabalha com muitos escritórios contábeis fornecendo ' + gancho + refExtra + ' que ajudam na organização do dia a dia — ' + detalhe + '.\n\nPosso te mostrar alguns modelos que costumam fazer sentido pra contabilidade?';
    }
  } else if (variante === 'B') {
    if (empresa && !temEmpresaNoNome) {
      msg = saudacao + '\n\nAqui é a ' + consultor + ', da Federal Malotes.\n\nTrabalho com escritórios como a ' + empresa + ' que buscam ' + gancho + ' pra passar uma imagem mais profissional no atendimento ao cliente.\n\nVocês já usam algum material personalizado no escritório?';
    } else {
      msg = saudacao + '\n\nAqui é a ' + consultor + ', da Federal Malotes.\n\nTrabalho com escritórios contábeis que buscam ' + gancho + ' pra passar uma imagem mais profissional no atendimento ao cliente.\n\nVocês já usam algum material personalizado no escritório?';
    }
  } else {
    if (empresa && !temEmpresaNoNome) {
      msg = saudacao + '\n\n' + consultor + ' aqui, da Federal Malotes.\n\nA gente produz ' + gancho + refExtra + ' com a marca do escritório. Vi que a ' + empresa + ' é do ramo contábil — muitos escritórios como o de vocês usam pra padronizar a comunicação com os clientes.\n\nFaz sentido eu te mostrar como funciona?';
    } else {
      msg = saudacao + '\n\n' + consultor + ' aqui, da Federal Malotes.\n\nA gente produz ' + gancho + refExtra + ' com a marca do escritório. Muitos contadores usam pra padronizar a comunicação com os clientes e manter tudo organizado.\n\nFaz sentido eu te mostrar como funciona?';
    }
  }
} else if (tipo === 'followup_1') {
  // ═══ FOLLOW-UP D+3 ═══
  const hi = nome ? 'Oi, ' + nome + '!' : 'Oi!';
  msg = hi + '\n\n' + consultor + ' aqui, da Federal Malotes. Te mandei uma mensagem uns dias atrás sobre ' + gancho + ' pra escritórios contábeis.\n\nQuer que eu te mande uns modelos pra dar uma olhada sem compromisso?';
} else if (tipo === 'followup_2') {
  // ═══ FOLLOW-UP D+7 ═══
  const hi = nome ? 'Oi, ' + nome + '!' : 'Oi!';
  msg = hi + '\n\nAqui é a ' + consultor + ', da Federal Malotes. Só passando pra ver se ainda faz sentido conversar sobre ' + gancho + ' pro escritório.\n\nSe quiser, posso mandar um catálogo rápido por aqui mesmo.';
}

// --- Fallback ---
if (!msg || msg.length < 50) {
  msg = saudacao + '\n\nAqui é a ' + consultor + ', assistente da Federal Malotes.\n\nA gente trabalha com escritórios contábeis fornecendo malotes e materiais personalizados que ajudam na organização do dia a dia.\n\nPosso te mostrar alguns modelos?';
}

// --- Truncar ---
if (msg.length > maxChars) {
  const cut = msg.substring(0, maxChars - 3);
  const nl = cut.lastIndexOf('\n');
  msg = nl > 200 ? cut.substring(0, nl) : cut + '...';
}

// --- Anti-alucinação ---
msg = msg.replace(/R\$\s*[\d.,]+/g, '[consulte valores]');

// --- Label da variante ---
const varLabel = tipo === 'primeiro_contato' ? variante : tipo.toUpperCase();

return [{ json: { ...item, mensagem: msg, variante: varLabel } }];

// Recupera dados do lead (não depende da saída do Sheets)
const lead = $('prepararDisparo').first().json;

const MIN_MINUTES = 2;
const MAX_MINUTES = 10;
const prev = Number(lead.TempoMsg);

function randInt(min, max) {
  return Math.floor(Math.random() * (max - min + 1)) + min;
}

let delaySeconds;
let tries = 0;
do {
  delaySeconds = randInt(MIN_MINUTES, MAX_MINUTES) * 60;
  tries++;
} while (Number.isFinite(prev) && delaySeconds === prev && tries < 50);

if (Number.isFinite(prev) && delaySeconds === prev) {
  const up = prev + 60;
  const down = prev - 60;
  if (up <= MAX_MINUTES * 60) delaySeconds = up;
  else if (down >= MIN_MINUTES * 60) delaySeconds = down;
}

return [{ json: { ...lead, delaySeconds } }];
